import React, { useState, useEffect } from 'react'; // Import useState and useEffect from React
import { Link, NavLink, useNavigate } from 'react-router-dom'; // Import useNavigate from react-router-dom
import styles from './ProfilePage.module.css'; // Import your CSS Module
import './accountpage.css';

const AccountNavigation = () => (
  <aside className="account-navigation">
    <h3>Account Navigation</h3>
    <ul>
      <li>
        <NavLink to="/account/profile" className={({ isActive }) => isActive ? 'active' : ''}>
          Your Profile
        </NavLink>
      </li>
      <li>
        <NavLink to="/account/orders" className={({ isActive }) => isActive ? 'active' : ''}>
          Your Orders
        </NavLink>
      </li>
      <li>
        <NavLink to="/account/addresses" className={({ isActive }) => isActive ? 'active' : ''}>
          Your Addresses
        </NavLink>
      </li>
      <li>
        <NavLink to="/account/payments" className={({ isActive }) => isActive ? 'active' : ''}>
          Payment Methods
        </NavLink>
      </li>
      <li>
        <NavLink to="/account/security" className={({ isActive }) => isActive ? 'active' : ''}>
          Login & Security
        </NavLink>
      </li>
      <li>
        <NavLink to="/account/help" className={({ isActive }) => isActive ? 'active' : ''}>
          Help & FAQ
        </NavLink>
      </li>
      {/* Add more navigation links here */}
    </ul>
  </aside>
);

const AccountContent = ({ children }) => (
  <div className="account-content">
    {children}
  </div>
);

const ProfilePageContent = () => {
  const [profile, setProfile] = useState({ // useState is now imported
    fullName: 'Loading...',
    email: 'Loading...',
    mobileNumber: null,
    username: 'Loading...',
  });
  const [error, setError] = useState(null);
  const navigate = useNavigate(); // useNavigate is now imported

  useEffect(() => { // useEffect is now imported
    // Set default profile initially
    const defaultProfile = {
      fullName: 'Guest User',
      email: 'guest@example.com',
      mobileNumber: null,
      username: 'guest',
    };
    setProfile(defaultProfile);

    // Fetch profile data from API
    fetch('/api/profile')
      .then(response => {
        if (!response.ok) {
          throw new Error(`Failed to fetch profile: ${response.status}`);
        }
        return response.json();
      })
      .then(data => {
        setProfile(data);
      })
      .catch(err => {
        console.error('Error fetching profile:', err);
        setError('Failed to load profile information.');
      });
  }, []);

  const handleEditProfileClick = () => {
    navigate('/edit-profile');
  };

  const handleAddMobile = () => {
    alert('Add mobile number functionality will be implemented here.');
  };

  return (
    <div className={styles.profileContainer}> {/* styles is now imported */}
      <div style={{ textAlign: 'right', marginBottom: '15px' }}>
        <button id="editProfileButton" className={styles.editButton} onClick={handleEditProfileClick}>
          Edit Profile
        </button>
      </div>
      <div className={styles.profileCard}>
        <h2>Your Profile</h2>
        <div className={styles.profileInfo}>
          <div className={styles.infoItem}>
            <span className={styles.label}>Name</span>
            <span className={styles.value}>{profile.fullName || 'N/A'}</span>
          </div>
          <div className={styles.infoItem}>
            <span className={styles.label}>Email</span>
            <span className={styles.value}>{profile.email || 'N/A'}</span>
          </div>
          <div className={styles.infoItem}>
            <span className={styles.label}>Primary mobile number</span>
            {profile.mobileNumber ? (
              <div className={styles.mobileInfo}>
                <span className={styles.value}>{profile.mobileNumber}</span>
                <p className={styles.securityNote}>
                  <span style={{ color: 'orange', fontSize: '1.2em' }}>⚠️</span>
                  For stronger account security, add your mobile number. If there's an
                  unusual sign-in, we'll text you and verify that it's really you.
                </p>
              </div>
            ) : (
              <button className={styles.addButton} onClick={handleAddMobile}>Add</button>
            )}
          </div>
          <div className={styles.infoItem}>
            <span className={styles.label}>Username</span>
            <span className={styles.value}>{profile.username || 'N/A'}</span>
          </div>
          <div className={styles.infoItem}>
            <span className={styles.label}>Password</span>
            <span className={styles.value}>********</span>
          </div>
        </div>
        {error && <p className={styles.errorMessage}>{error}</p>}
      </div>
    </div>
  );
};

const ProfilePage = () => (
  <div className="account-container page" id="account-page">
    <AccountNavigation />
    <AccountContent>
      <ProfilePageContent />
    </AccountContent>
  </div>
);

export default ProfilePage;
